add_action( 'init', function() {
    wp_register_script_module( 'demo/nav', includes_url( 'js/wp-util.js' ) ); // placeholder URL available in core.
    wp_interactivity()->add_client_navigation_support_to_script_module( 'demo/nav' );
    wp_enqueue_script_module( 'demo/nav' );
} );

function wpbp_router_link( string $url, string $text ): string {
    $home    = wp_parse_url( home_url() );
    $target  = wp_parse_url( $url );
    $is_external = $target && ( ($target['host'] ?? '') !== ($home['host'] ?? '') || ($target['scheme'] ?? '') !== ($home['scheme'] ?? '') );
    $rel = $is_external ? ' rel="nofollow"' : '';
    return sprintf(
        '<a href="%s" data-wp-router-replace="true" data-wp-router-prefetch="intent"%s>%s</a>',
        esc_url( $url ),
        $rel,
        esc_html( $text )
    );
}
